template <typename T>
void check(T value) {
    if constexpr (is_same_v<T, int>) {
        if (value < 0)
            throw runtime_error("Negative integer not allowed");
    }

    cout << "Value = " << value << endl;
}

int main() {
    try {
        check(10);
        check(-5);
    }
    catch (const exception& e) {
        cout << e.what();
    }
}

